/// Decode a 2-byte EUC-JP code to a Unicode scalar, or `None` if unmapped.
pub fn eucjp_to_unicode(code: u16) -> Option<char> {
    EUCJP_TO_UNICODE
        .binary_search_by_key(&code, |&(c, _)| c)
        .ok()
        .and_then(|i| char::from_u32(EUCJP_TO_UNICODE[i].1 as u32))
}
